37	inline void to_json(nlohmann::json& j, const Lens& lens) {
38		if (lens.mode == ELensMode::OpenCV) {
39			j["is_fisheye"] = false;
40			j["k1"] = lens.params[0];
41			j["k2"] = lens.params[1];
42			j["p1"] = lens.params[2];
43			j["p2"] = lens.params[3];
44		} else if (lens.mode == ELensMode::OpenCVFisheye) {
45			j["is_fisheye"] = true;
46			j["k1"] = lens.params[0];
47			j["k2"] = lens.params[1];
48			j["k3"] = lens.params[2];
49			j["k4"] = lens.params[3];
50		} else if (lens.mode == ELensMode::FTheta) {
51			j["ftheta_p0"] = lens.params[0];
52			j["ftheta_p1"] = lens.params[1];
53			j["ftheta_p2"] = lens.params[2];
54			j["ftheta_p3"] = lens.params[3];
55			j["ftheta_p4"] = lens.params[4];
56			j["w"] = lens.params[5];
57			j["h"] = lens.params[6];
58		} else if (lens.mode == ELensMode::LatLong) {
59			j["latlong"] = true;
60		} else if (lens.mode == ELensMode::Equirectangular) {
61			j["equirectangular"] = true;
62		} else if (lens.mode == ELensMode::Orthographic) {
63			j["orthographic"] = true;
64		}
65	}
