68		if (j.contains("k1")) {
69			if (j.value("is_fisheye", false)) {
70				lens.mode = ELensMode::OpenCVFisheye;
71				lens.params[0] = j.at("k1");
72				lens.params[1] = j.at("k2");
73				lens.params[2] = j.at("k3");
74				lens.params[3] = j.at("k4");
75			} else {
76				lens.mode = ELensMode::OpenCV;
77				lens.params[0] = j.at("k1");
78				lens.params[1] = j.at("k2");
79				lens.params[2] = j.at("p1");
80				lens.params[3] = j.at("p2");
81			}
82		} else if (j.contains("ftheta_p0")) {
83			lens.mode = ELensMode::FTheta;
84			lens.params[0] = j.at("ftheta_p0");
85			lens.params[1] = j.at("ftheta_p1");
86			lens.params[2] = j.at("ftheta_p2");
87			lens.params[3] = j.at("ftheta_p3");
88			lens.params[4] = j.at("ftheta_p4");
89			lens.params[5] = j.at("w");
90			lens.params[6] = j.at("h");
91		} else if (j.contains("latlong")) {
92			lens.mode = ELensMode::LatLong;
93		} else if (j.contains("equirectangular")) {
94			lens.mode = ELensMode::Equirectangular;
95		} else if (j.contains("orthographic")) {
96			lens.mode = ELensMode::Orthographic;
97		} else {
98			lens.mode = ELensMode::Perspective;
99		}
