153			if (j.contains("image_resolution")) dataset.metadata[i].resolution = j.at("image_resolution");
154	
155			dataset.xforms[i] = j.at("xforms").at(i);
156			if (j.contains("focal_lengths")) dataset.metadata[i].focal_length = j.at("focal_lengths").at(i);
157			if (j.contains("metadata")) {
158				auto &ji = j["metadata"].at(i);
159				dataset.metadata[i].resolution = ji.at("resolution");
160				dataset.metadata[i].focal_length = ji.at("focal_length");
161				dataset.metadata[i].principal_point = ji.at("principal_point");
162				if (ji.contains("lens")) dataset.metadata[i].lens = ji.at("lens");
163				// Legacy: "lens" used to be called "camera_distortion"
164				if (ji.contains("camera_distortion")) dataset.metadata[i].lens = ji.at("camera_distortion");
165			}
166		}
167	
168		dataset.render_aabb = j.at("render_aabb");
169		dataset.render_aabb_to_local = mat3::identity();
170		if (j.contains("render_aabb_to_local")) dataset.render_aabb_to_local = j.at("render_aabb_to_local");
171	
172		dataset.up = j.at("up");
173		dataset.offset = j.at("offset");
174		dataset.envmap_resolution = j.at("envmap_resolution");
175		dataset.scale = j.at("scale");
176		dataset.aabb_scale = j.at("aabb_scale");
177		dataset.from_mitsuba = j.at("from_mitsuba");
178		dataset.is_hdr = j.value("is_hdr", false);
179	
180		if (j.contains("wants_importance_sampling")) {
181			dataset.wants_importance_sampling = j.at("wants_importance_sampling");
182		} else {
183			dataset.wants_importance_sampling = true;
