86	json merge_parent_network_config(const json& child, const fs::path& child_path) {
87		if (!child.contains("parent")) {
88			return child;
89		}
90		fs::path parent_path = child_path.parent_path() / std::string(child["parent"]);
91		tlog::info() << "Loading parent network config from: " << parent_path.str();
92		std::ifstream f{native_string(parent_path)};
93		json parent = json::parse(f, nullptr, true, true);
94		parent = merge_parent_network_config(parent, parent_path);
95		parent.merge_patch(child);
96		return parent;
97	}
