99	std::string get_filename_in_data_path_with_suffix(fs::path data_path, fs::path network_config_path, const char* suffix) {
100		// use the network config name along with the data path to build a filename with the requested suffix & extension
101		std::string default_name = network_config_path.basename();
102		if (default_name == "") {
103			default_name = "base";
104		}
105	
106		if (data_path.empty()) {
107			return default_name + std::string(suffix);
108		}
109	
110		if (data_path.is_directory()) {
111			return (data_path / (default_name + std::string{suffix})).str();
112		}
113	
114		return data_path.stem().str() + "_" + default_name + std::string(suffix);
115	}
